  "sol_3_effect": ["Dopasowanie do realiów produkcji, skalowalność i szybkie iteracje.", "Dopasowanie do realiów produkcji.", "Dopasowanie do realiów fabryce, skalowalność i szybkie iteracje."],
  "sol_3_diff": ["Podejście PoC-first: nie przepalasz budżetu zanim nie ma potwierdzenia sensu.", "PoC-first: najpierw dowód wartości, dopiero potem skala.", "Minimalny sensowny zakres na start — bez przepalania budżetu."],
