  "serv_item_workshop_val": ["Warsztat, który kończy się roadmapą i KPI — wybierasz use-case’y z realnym potencjałem ROI.", "Warsztat, który kończy się roadmapą i KPI.", "Warsztat — który kończy się roadmapą i KPI — wybierasz use-case’y z realnym potencjałem ROI."],
  "serv_item_workshop_trig": ["Czujesz presję związaną z Przemysłem 4.0, ale nie wiesz od czego zacząć. Chcesz przetestować AI w swoim biznesie.", "Czujesz presję związaną z Przemysłem 4.0, ale nie wiesz od czego zacząć.", "Czujesz presję związaną z Przemysłem 4.0 — ale nie wiesz od czego zacząć. Chcesz przetestować AI w swoim biznesie."],
  "serv_item_workshop_btn": ["Umów warsztat", "Zarezerwuj warsztat", "Start: warsztat"],
  "serv_workshop_desc": ["Przeprowadzamy intensywne warsztaty, na których zderzamy Twoje wyzwania biznesowe z możliwościami technologii. Nasi eksperci dobierają use-cases z najwyższym potencjałem zwrotu z inwestycji (ROI).", "Przeprowadzamy intensywne warsztaty, na których zderzamy Twoje wyzwania biznesowe z możliwościami technologii.", "Przeprowadzamy intensywne warsztaty — na których zderzamy Twoje wyzwania biznesowe z możliwościami technologii. Nasi eksperci dobierają use-cases z najwyższym potencjałem zwrotu z inwestycji (ROI)."],
  "serv_workshop_forWho": ["Średnie przedsiębiorstwa produkcyjne, logistyczne, usługowe i retail. CEO, COO, IT Managerowie.", "Średnie przedsiębiorstwa produkcyjne, logistyczne, usługowe i retail.", "Średnie firmy: produkcja, logistyka, retail — szczególnie operacje/transformacja/IT."],
  "serv_workshop_when": ["Czujesz presję na automatyzację/AI, chcesz zwiększyć możliwości optymalizacji wewnętrznych procesów, ale obawiasz się ryzyka i 'przepalenia' budżetu na niesprawdzone pomysły.", "Czujesz presję na automatyzację/AI.", "Gdy AI jest na radarze, ale brakuje jasnego punktu startu i ROI."],
  "serv_workshop_what": ["Wytwarzamy 'Business Needs & Vision'. Otrzymujesz udokumentowane KPI oraz Raport po AI Workshop z podsumowaniem, rekomendacjami wdrożeniowymi i roadmapą.", "Wytwarzamy 'Business Needs & Vision'.", "Priorytety + lista use-case’ów + rekomendacje danych/integracji + roadmapa."],
  "serv_workshop_effect": ["Celem warsztatów jest zidentyfikowanie w Twojej firmie procesów i pomysłów, które mogą przynieść praktyczne korzyści. Otrzymujesz profesjonalnie opracowany raport stanowiący gotowy plan działania (Roadmap).", "Celem warsztatów jest zidentyfikowanie w Twojej firmie procesów i pomysłów, które mogą przynieść praktyczne korzyści.", "Szybciej podejmujesz decyzje, ograniczasz ryzyko i dostajesz konkretną roadmapę kolejnych kroków."],
  "serv_workshop_diff": ["Wykorzystujemy naszą autorską metodologię pozwalającą na szybkie (10 dni) i precyzyjne określenie najbardziej obiecujących obszarów, które przyniosą realne ROI (np. 95% wzrost efektywności w wybranych procesach).", "Wykorzystujemy naszą autorską metodologię pozwalającą na szybkie (10 dni) i precyzyjne określenie najbardziej obiecujących obszarów, które przyniosą realne ROI (np.", "Pragmatyczne podejście: mierzalne KPI i szybki start."],
  "serv_workshop_process": ["1. Analiza business needs & vision (Pre-work)\\n2. Warsztaty stacjonarne (Brainstorming & Filtering)\\n3. Weryfikacja techniczna i analiza wykonalności\\n4. Raport końcowy z roadmapą i estymacją.", "• Analiza business needs & vision (Pre-work)\\n• Warsztaty stacjonarne (Brainstorming & Filtering)\\n• Weryfikacja techniczna i analiza wykonalności\\n• Raport końcowy z roadmapą i estymacją.", "Krok 1: Analiza business needs & vision (Pre-work)\\nKrok 2: Warsztaty stacjonarne (Brainstorming & Filtering)\\nKrok 3: Weryfikacja techniczna i analiza wykonalności\\nKrok 4: Raport końcowy z roadmapą i estymacją."],
  "serv_workshop_artifacts": ["Raport Strategiczny, Lista Priorytetowych Use-Cases, Analiza ROI/TCO, Roadmapa Wdrożenia, Rekomendacje Architektoniczne.", "Raport Strategiczny — Lista Priorytetowych Use-Cases", "Raport Strategiczny."],
  "serv_item_proto_title": ["AI Prototyping & Product Discovery", "Case study: AI Prototyping & Product Discovery", "AI Prototyping & Product Discovery — case study"],
  "serv_item_proto_val": ["Discovery + prototyp do testów z użytkownikami — zanim wejdziesz w pełne wdrożenie.", "Discovery + prototyp do testów z użytkownikami.", "W skrócie: Discovery + prototyp do testów z użytkownikami — zanim wejdziesz w pełne wdrożenie."],
  "serv_item_proto_trig": ["Chcesz zidentyfikować konkretne zastosowania, które przyniosą mierzalne ROI, a nie tylko innowację dla innowacji.", "Chcesz zidentyfikować konkretne zastosowania.", "Chcesz zidentyfikować konkretne zastosowania — które przyniosą mierzalne ROI"],
  "serv_item_proto_btn": ["Zróbmy prototyp", "Zacznijmy od PoC", "Umówmy prototyp"],
  "serv_proto_desc": ["Solution Discovery Product: Warsztaty i sprinty, które mają na celu zderzenie koncepcji aplikacji z rzeczywistością. Następnie nasz ekspert pomaga przygotować prototyp (PoC) w celu weryfikacji na produkcji.", "Solution Discovery Product: Warsztaty i sprinty, które mają na celu zderzenie koncepcji aplikacji z rzeczywistością.", "Solution Discovery Product: Warsztaty i sprinty, które mają na celu zderzenie koncepcji aplikacji z rzeczywistością. Następnie nasz ekspert pomaga przygotować prototyp (PoC) w celu weryfikacji na hali."],
  "serv_proto_forWho": ["Duże przedsiębiorstwa produkcyjne, logistyczne. IT Director, Head of Innovation, Transformation Manager, R&D Lead.", "Duże przedsiębiorstwa produkcyjne, logistyczne.", "Duże organizacje z zespołami IT/transformacji/innowacji."],
  "serv_proto_when": ["Masz pomysł, ale potrzebujesz weryfikacji w realnym środowisku (na hali). Chcesz uniknąć dużych strat związanych z wdrożeniem systemu, którego nikt nie będzie używał.", "Masz pomysł, ale potrzebujesz weryfikacji w realnym środowisku (na hali).", "Gdy chcesz usprawnić proces i szybko policzyć efekt w pilocie."],
  "serv_proto_what": ["Weryfikacja pomysłu: przygotowujemy prototyp (PoC) w 48h-5dni, dokumentację oraz przeprowadzamy testy z użytkownikami (User Testing) w warunkach operacyjnych.", "Weryfikacja pomysłu: przygotowujemy prototyp (PoC) w 48h-5dni.", "PoC/prototyp + backlog funkcji + plan pilotażu i skalowania."],
  "serv_proto_effect": ["Stworzenie prototypu pozwala na przetestowanie pomysłu na wczesnym etapie. Oszczędność czasu i budżetu dzięki eliminacji błędnych założeń (Fail Fast). Decyzja o wdrożeniu oparta o twarde dane.", "Stworzenie prototypu pozwala na przetestowanie pomysłu na wczesnym etapie.", "Wymierne korzyści w codziennej pracy — bez komplikowania procesu."],
  "serv_proto_diff": ["Wiedza ekspercka z zakresu przemysłu i UX. Rozumienie problemów technologicznych i wyzwań specyficznych dla branży. Skupiamy się na biznesie i potrzebach realnych użytkowników (operatorów), nie tylko na technologii.", "Wiedza ekspercka z zakresu przemysłu i UX.", "Pragmatyczne podejście: mierzalne KPI i szybki start."],
  "serv_proto_process": ["1. Discovery Workshop\\n2. Rapid Prototyping (Low/High Fidelity)\\n3. User Testing na hali produkcyjnej\\n4. Feedback Loop & Iteracja\\n5. Final Report & Go/No-Go Decision.", "• Discovery Workshop\\n• Rapid Prototyping (Low/High Fidelity)\\n• User Testing na hali produkcyjnej\\n• Feedback Loop & Iteracja\\n• Final Report & Go/No-Go Decision.", "Krok 1: Discovery Workshop\\nKrok 2: Rapid Prototyping (Low/High Fidelity)\\nKrok 3: User Testing na hali produkcyjnej\\nKrok 4: Feedback Loop & Iteracja\\nKrok 5: Final Report & Go/No-Go Decision."],
  "serv_proto_artifacts": ["Klikalny prototyp (Figma/Web/Tablet), Raport z testów użyteczności (Video/Heatmaps), Backlog produktowy, Estymacja kosztów pełnego wdrożenia.", "Klikalny prototyp (Figma/Web/Tablet) — Raport z testów użyteczności (Video/Heatmaps)", "Klikalny prototyp (Figma/Web/Tablet)."],
